import { App, PluginSettingTab, Setting, Notice } from "obsidian";
import SyncSavePlugin from "../../main";
import { BoxProvider } from "../providers/BoxProvider";
import { generateCodeVerifier, generateCodeChallenge } from "../utils/pkce";

const PROVIDER_ICONS = {
  s3: "data:image/png;base64,",
  box: "data:image/png;base64,",
  dropbox: "data:image/png;base64,",
  googledrive: "data:image/png;base64,",
  onedrive: "data:image/png;base64,"
};

export class SyncSaveSettingsTab extends PluginSettingTab {
  private plugin: SyncSavePlugin;

  constructor(app: App, plugin: SyncSavePlugin) {
    super(app, plugin);
    this.plugin = plugin;
  }

  display(): void {
    const { containerEl } = this;
    containerEl.empty();

    this.renderHeader();
    this.renderProviderSelection();
    this.renderProviderSettings();
    this.renderSyncSettings();
    this.renderAdvancedSettings();
    this.renderSyncHistory();
  }

  private renderHeader(): void {
    const { containerEl } = this;
    const header = containerEl.createDiv({ cls: "sync-settings-header" });

    header.createEl("h2", { text: "同步備份" });

    const service = this.plugin.settings.activeProvider;
    const badge = header.createSpan({ cls: "sync-header-badge" });

    let isConfiguredAndEnabled = false;
    if (service && this.plugin.settings.enabledProviders.includes(service)) {
      // 檢查該雲端是否已填寫必要欄位
      const s = this.plugin.settings;
      if (service === "s3" && s.s3.endpoint && s.s3.bucket && s.s3.accessKeyId && s.s3.secretAccessKey) {
        isConfiguredAndEnabled = true;
      } else if (service === "webdav" && s.webdav.url && s.webdav.username && s.webdav.password) {
        isConfiguredAndEnabled = true;
      } else if (service === "dropbox" && s.dropbox.accessToken) {
        isConfiguredAndEnabled = true;
      } else if (service === "onedrive" && s.onedrive.accessToken) {
        isConfiguredAndEnabled = true;
      } else if (service === "googledrive" && (s.googledrive.accessToken || s.googledrive.refreshToken)) {
        isConfiguredAndEnabled = true;
      } else if (service === "box" && (s.box.accessToken || s.box.refreshToken)) {
        isConfiguredAndEnabled = true;
      }
    }

    if (service && isConfiguredAndEnabled) {
      badge.addClass("connected");
      badge.setText(`已連線 · ${service.toUpperCase()}`);
    } else {
      badge.addClass("disconnected");
      badge.setText("未連線");
    }

    const btnGroup = header.createDiv();
    btnGroup.style.cssText = "margin-left: auto; display: flex; gap: 8px;";

    const syncBtn = btnGroup.createEl("button", { cls: "sync-btn sync-btn-primary", text: "立即同步" });
    syncBtn.addEventListener("click", () => {
      this.plugin.manualSync();
    });

    const testBtn = btnGroup.createEl("button", { cls: "sync-btn sync-btn-secondary", text: "測試連線" });
    testBtn.addEventListener("click", () => {
      this.plugin.testConnection();
    });
  }

  private renderProviderSelection(): void {
    const { containerEl } = this;

    const section = containerEl.createDiv({ cls: "sync-section" });
    const title = section.createDiv({ cls: "sync-section-title" });
    title.setText("雲端服務");

    const grid = section.createDiv({ cls: "sync-provider-grid" });

    const providers = [
      { id: "s3", name: "S3-Compatible", icon: "☁️", desc: "AWS S3, R2, B2" },
      { id: "webdav", name: "WebDAV", icon: "🗄️", desc: "NextCloud, Synology" },
      { id: "dropbox", name: "Dropbox", icon: "📦", desc: "OAuth 2.0" },
      { id: "onedrive", name: "OneDrive", icon: "☁️", desc: "Microsoft Graph" },
      { id: "googledrive", name: "Google Drive", icon: "🔷", desc: "Google API v3" },
      { id: "box", name: "Box", icon: "📦", desc: "Box API v2" },
    ];

    for (const p of providers) {
      const card = grid.createDiv({
        cls: `sync-provider-card${this.plugin.settings.activeProvider === p.id ? " active" : ""}`,
      });
      card.dataset.provider = p.id;
      card.addEventListener("click", () => {
        this.plugin.settings.activeProvider = p.id;
        this.plugin.saveSettings();
        this.display();
      });

      const customIcon = PROVIDER_ICONS[p.id as keyof typeof PROVIDER_ICONS];
      if (customIcon) {
        const iconDiv = card.createDiv({ cls: "sync-provider-icon" });
        iconDiv.style.setProperty("background", "transparent", "important");
        const img = iconDiv.createEl("img");
        img.src = customIcon;
        img.style.cssText = "width: 32px; height: 32px; object-fit: contain;";
      } else {
        card.createDiv({ cls: "sync-provider-icon", text: p.icon });
      }
      card.createDiv({ cls: "sync-provider-name", text: p.name });
      
      const badgeText = this.plugin.settings.enabledProviders.includes(p.id) 
        ? `${p.desc} (已啟用)` 
        : p.desc;
      
      const badge = card.createDiv({ cls: "sync-provider-badge", text: badgeText });
      if (this.plugin.settings.enabledProviders.includes(p.id)) {
        badge.style.color = "var(--sync-success)";
        badge.style.fontWeight = "bold";
      }
    }
  }

  private renderProviderSettings(): void {
    const { containerEl } = this;

    const section = containerEl.createDiv({ cls: "sync-section" });

    const provider = this.plugin.settings.activeProvider;
    if (!provider) {
      const empty = section.createDiv({ cls: "sync-empty-state" });
      const emptyIcon = empty.createDiv({ text: "☁️" });
      emptyIcon.style.cssText = "font-size: 32px; opacity: 0.5;";
      empty.createDiv({ cls: "sync-empty-state-text", text: "請在上方選擇一個雲端服務來設定同步" });
      return;
    }

    const title = section.createDiv({ cls: "sync-section-title" });
    const icon = provider === "s3" ? "☁️" : provider === "webdav" ? "🗄️" : provider === "dropbox" ? "📦" : provider === "googledrive" ? "🔷" : provider === "box" ? "📦" : "☁️";
    title.setText(`${icon}  ${provider.toUpperCase()} 設定`);

    const card = section.createDiv({ cls: "sync-card" });

    // 新增「啟用此雲端同步」的開關在最上方
    const isEnabled = this.plugin.settings.enabledProviders.includes(provider);
    this.toggleField(card, "啟用此雲端同步", `將此 Obsidian 筆記庫同步備份到 ${provider.toUpperCase()}`, isEnabled, (v) => {
      if (v) {
        if (!this.plugin.settings.enabledProviders.includes(provider)) {
          this.plugin.settings.enabledProviders.push(provider);
        }
      } else {
        this.plugin.settings.enabledProviders = this.plugin.settings.enabledProviders.filter(p => p !== provider);
      }
      this.plugin.saveSettings();
      this.display();
    });

    const divider = card.createDiv({ cls: "sync-settings-divider" });
    divider.style.margin = "12px 0";

    if (provider === "s3") {
      this.renderS3Settings(card);
    } else if (provider === "webdav") {
      this.renderWebDAVSettings(card);
    } else if (provider === "dropbox") {
      this.renderDropboxSettings(card);
    } else if (provider === "onedrive") {
      this.renderOneDriveSettings(card);
    } else if (provider === "googledrive") {
      this.renderGoogleDriveSettings(card);
    } else if (provider === "box") {
      this.renderBoxSettings(card);
    }
  }

  private renderS3Settings(container: HTMLElement): void {
    const s = this.plugin.settings.s3;

    this.inputField(container, "端點網址", s.endpoint, (v) => {
      this.plugin.settings.s3.endpoint = v;
      this.plugin.saveSettings();
    }, "https://s3.us-east-1.amazonaws.com");

    this.formRow(container, () => {
      this.inputField(container, "區域", s.region, (v) => {
        this.plugin.settings.s3.region = v;
        this.plugin.saveSettings();
      }, "us-east-1");

      this.inputField(container, "儲存桶", s.bucket, (v) => {
        this.plugin.settings.s3.bucket = v;
        this.plugin.saveSettings();
      }, "my-vault");
    });

    this.inputField(container, "存取金鑰 ID", s.accessKeyId, (v) => {
      this.plugin.settings.s3.accessKeyId = v;
      this.plugin.saveSettings();
    });

    this.inputField(container, "秘密存取金鑰", s.secretAccessKey, (v) => {
      this.plugin.settings.s3.secretAccessKey = v;
      this.plugin.saveSettings();
    }, undefined, "password");

    this.inputField(container, "前綴路徑（選填）", s.prefix, (v) => {
      this.plugin.settings.s3.prefix = v;
      this.plugin.saveSettings();
    }, "my-vault/");
  }

  private renderWebDAVSettings(container: HTMLElement): void {
    const s = this.plugin.settings.webdav;

    this.inputField(container, "伺服器網址", s.url, (v) => {
      this.plugin.settings.webdav.url = v;
      this.plugin.saveSettings();
    }, "https://nextcloud.example.com/remote.php/dav/files/");

    this.inputField(container, "同步路徑", s.path, (v) => {
      this.plugin.settings.webdav.path = v;
      this.plugin.saveSettings();
    }, "SyncSave");

    this.inputField(container, "使用者名稱", s.username, (v) => {
      this.plugin.settings.webdav.username = v;
      this.plugin.saveSettings();
    });

    this.inputField(container, "密碼", s.password, (v) => {
      this.plugin.settings.webdav.password = v;
      this.plugin.saveSettings();
    }, undefined, "password");
  }

  private renderDropboxSettings(container: HTMLElement): void {
    const s = this.plugin.settings.dropbox;

    this.inputField(container, "存取權杖", s.accessToken, (v) => {
      this.plugin.settings.dropbox.accessToken = v;
      this.plugin.saveSettings();
    }, "sl.B...");

    const toggleGroup = container.createDiv({ cls: "sync-form-group" });
    const toggleRow = toggleGroup.createDiv({ cls: "sync-toggle-row" });
    const toggleInfo = toggleRow.createDiv({ cls: "sync-toggle-info" });
    toggleInfo.createDiv({ cls: "sync-toggle-label", text: "使用應用程式資料夾" });
    toggleInfo.createDiv({ cls: "sync-toggle-desc", text: "僅存取 Dropbox 中的 SyncSave 應用程式資料夾" });

    const toggle = toggleRow.createEl("input", { type: "checkbox", attr: { "data-toggle": "" } });
    toggle.checked = s.appFolder;
    toggle.addEventListener("change", () => {
      this.plugin.settings.dropbox.appFolder = toggle.checked;
      this.plugin.saveSettings();
    });

    const helpText = container.createDiv({
      cls: "sync-connection-status",
      text: "前往 https://www.dropbox.com/developers/apps 取得權杖",
    });
    helpText.style.cssText = "background: rgba(251, 191, 36, 0.08); border: 1px solid rgba(251, 191, 36, 0.2); color: var(--text-muted);";
  }

  private renderOneDriveSettings(container: HTMLElement): void {
    const s = this.plugin.settings.onedrive;

    this.inputField(container, "存取權杖", s.accessToken, (v) => {
      this.plugin.settings.onedrive.accessToken = v;
      this.plugin.saveSettings();
    });

    const toggleGroup = container.createDiv({ cls: "sync-form-group" });
    const toggleRow = toggleGroup.createDiv({ cls: "sync-toggle-row" });
    const toggleInfo = toggleRow.createDiv({ cls: "sync-toggle-info" });
    toggleInfo.createDiv({ cls: "sync-toggle-label", text: "使用應用程式資料夾" });
    toggleInfo.createDiv({ cls: "sync-toggle-desc", text: "僅同步到 OneDrive 中的 SyncSave 應用程式資料夾" });

    const toggle = toggleRow.createEl("input", { type: "checkbox", attr: { "data-toggle": "" } });
    toggle.checked = s.useAppFolder;
    toggle.addEventListener("change", () => {
      this.plugin.settings.onedrive.useAppFolder = toggle.checked;
      this.plugin.saveSettings();
    });
  }

  private renderGoogleDriveSettings(container: HTMLElement): void {
    const s = this.plugin.settings.googledrive;
    this.inputField(container, "用戶端 ID (Client ID - 選填)", s.clientId || "", (v) => {
      this.plugin.settings.googledrive.clientId = v;
      this.plugin.saveSettings();
    }, "留空將使用預設公開憑證");

    this.inputField(container, "用戶端金鑰 (Client Secret - 選填)", s.clientSecret || "", (v) => {
      this.plugin.settings.googledrive.clientSecret = v;
      this.plugin.saveSettings();
    }, "使用預設公開憑證時請留空", "password");

    // 產生授權連結按鈕
    const authLinkBtnGroup = container.createDiv();
    authLinkBtnGroup.style.cssText = "margin: 8px 0; display: flex; gap: 8px;";
    const genLinkBtn = authLinkBtnGroup.createEl("button", { cls: "sync-btn sync-btn-secondary", text: "1. 產生授權連結" });
    genLinkBtn.addEventListener("click", async () => {
      const clientId = s.clientId || "147064468840-cqaqbijf1g60e6k2sonu18rr8jt30gkh.apps.googleusercontent.com";
      const verifier = generateCodeVerifier();
      this.plugin.settings.googledrive.codeVerifier = verifier;
      await this.plugin.saveSettings();

      const challenge = await generateCodeChallenge(verifier);
      const authUrl = `https://accounts.google.com/o/oauth2/v2/auth?response_type=code&client_id=${clientId}&redirect_uri=http://localhost&scope=https://www.googleapis.com/auth/drive&access_type=offline&prompt=consent&code_challenge=${challenge}&code_challenge_method=S256`;
      window.open(authUrl, "_blank");
    });

    // 授權碼輸入框與啟用按鈕
    let authCode = "";
    const codeGroup = container.createDiv({ cls: "sync-form-group" });
    codeGroup.createDiv({ cls: "sync-form-label", text: "2. 授權碼 (Authorization Code)" });
    const codeRow = codeGroup.createDiv();
    codeRow.style.cssText = "display: flex; gap: 8px;";
    const codeInput = codeRow.createEl("input", {
      cls: "sync-input",
      type: "text",
      attr: { placeholder: "將跳轉後網址中的 ?code= 後方的代碼貼在此處" },
    });
    codeInput.style.flex = "1";
    codeInput.addEventListener("input", () => {
      let val = codeInput.value.trim();
      if (val.includes("code=")) {
        const match = val.match(/[?&]code=([^&]+)/);
        if (match) {
          val = match[1];
        }
      }
      authCode = val;
    });

    const exchangeBtn = codeRow.createEl("button", { cls: "sync-btn sync-btn-primary", text: "3. 啟用驗證" });
    exchangeBtn.addEventListener("click", async () => {
      let finalCode = authCode.trim();
      if (finalCode.includes("code=")) {
        const match = finalCode.match(/[?&]code=([^&]+)/);
        if (match) {
          finalCode = match[1];
        }
      }
      try {
        finalCode = decodeURIComponent(finalCode);
      } catch {}

      if (!finalCode) {
        new Notice("請先輸入授權碼");
        return;
      }
      const provider = this.plugin.getProvider();
      if (provider && provider.name === "Google Drive") {
        const res = await (provider as any).authorizeWithCode(finalCode, s.codeVerifier);
        new Notice(res.message);
        if (res.success) {
          this.plugin.settings.googledrive.codeVerifier = "";
          this.plugin.saveSettings();
          this.display();
        }
      }
    });

    const helpText = container.createDiv({
      cls: "sync-connection-status",
      text: "說明：此為個人開發工具，若在授權時看見「Google 未驗證」警告，請點選「進階」並選擇「繼續前往」，此屬正常現象。\n\n預設使用 PKCE 免金鑰流程。點擊「1. 產生授權連結」並於瀏覽器登入授權。授權完成後網頁會跳轉至 `http://localhost/?code=...` 並顯示「無法連上這個網站」（此為正常現象），請複製網址列 `code=` 後方的代碼，貼到下方輸入框點擊「3. 啟用驗證」即可完成綁定與自動刷新。亦可自訂輸入 Client ID/Secret 進行驗證。",
    });
    helpText.style.cssText = "background: rgba(251, 191, 36, 0.08); border: 1px solid rgba(251, 191, 36, 0.2); color: var(--text-muted); white-space: pre-line;";
  }

  private renderBoxSettings(container: HTMLElement): void {
    const s = this.plugin.settings.box;
    if (!s.authType) s.authType = "one_click";

    const authGroup = container.createDiv({ cls: "sync-form-group" });
    authGroup.createDiv({ cls: "sync-form-label", text: "驗證方式" });
    const authSelect = authGroup.createEl("select", { cls: "sync-input" });
    const authOptions = [
      { value: "one_click", label: "一鍵連結 (One-Click OAuth2 - 推薦，免輸入金鑰)" },
      { value: "oauth2", label: "用戶自訂驗證 (OAuth 2.0 - 自行輸入 Client ID 與 Secret)" },
    ];
    for (const opt of authOptions) {
      const el = authSelect.createEl("option", { value: opt.value, text: opt.label });
      if (opt.value === s.authType) el.selected = true;
    }
    authSelect.addEventListener("change", () => {
      this.plugin.settings.box.authType = authSelect.value;
      this.plugin.saveSettings();
      this.display();
    });

    if (s.authType === "one_click") {
      this.inputField(container, "授權中繼伺服器網址 (Auth Helper URL - 選填)", s.authHelperUrl || "", (v) => {
        this.plugin.settings.box.authHelperUrl = v;
        this.plugin.saveSettings();
      }, "https://sync-save-auth.vercel.app");

      const btnGroup = container.createDiv();
      btnGroup.style.cssText = "margin: 12px 0; display: flex; flex-direction: column; gap: 8px;";
      
      const connectBtn = btnGroup.createEl("button", { 
        cls: "sync-btn sync-btn-primary", 
        text: s.accessToken ? "重新連結 Box 帳號" : "連結至 Box 帳號" 
      });
      connectBtn.addEventListener("click", () => {
        const helperUrl = s.authHelperUrl || "https://sync-save-auth.vercel.app";
        const authUrl = `${helperUrl}/api/box/authorize`;
        window.open(authUrl, "_blank");
      });

      if (s.accessToken) {
        const disconnectBtn = btnGroup.createEl("button", { 
          cls: "sync-btn sync-btn-secondary", 
          text: "中斷 Box 連結" 
        });
        disconnectBtn.style.color = "var(--text-error)";
        disconnectBtn.addEventListener("click", () => {
          this.plugin.settings.box.accessToken = "";
          this.plugin.settings.box.refreshToken = "";
          this.plugin.saveSettings();
          new Notice("已中斷 Box 連結");
          this.display();
        });
      }

      const helpText = container.createDiv({
        cls: "sync-connection-status",
        text: "說明：一鍵連結需要中繼伺服器。請先依照專案下的 auth-helper 說明部署至 Vercel，並將你部署的 URL 填入「授權中繼伺服器網址」（若使用預設中繼網址，請確認其已正確設定且非 404）。點擊「連結至 Box 帳號」完成後會自動回彈綁定。",
      });
      helpText.style.cssText = "background: rgba(251, 191, 36, 0.08); border: 1px solid rgba(251, 191, 36, 0.2); color: var(--text-muted);";

    } else {
      this.inputField(container, "用戶端 ID (Client ID)", s.clientId || "", (v) => {
        this.plugin.settings.box.clientId = v;
        this.plugin.saveSettings();
      }, "輸入 Custom App 的 Client ID");

      this.inputField(container, "用戶端金鑰 (Client Secret)", s.clientSecret || "", (v) => {
        this.plugin.settings.box.clientSecret = v;
        this.plugin.saveSettings();
      }, "輸入 Custom App 的 Client Secret", "password");

      // 產生授權連結按鈕
      const authLinkBtnGroup = container.createDiv();
      authLinkBtnGroup.style.cssText = "margin: 8px 0; display: flex; gap: 8px;";
      const genLinkBtn = authLinkBtnGroup.createEl("button", { cls: "sync-btn sync-btn-secondary", text: "1. 產生授權連結" });
      genLinkBtn.addEventListener("click", () => {
        if (!s.clientId) {
          new Notice("請先填入 Client ID");
          return;
        }
        const authUrl = `https://account.box.com/api/oauth2/authorize?response_type=code&client_id=${s.clientId}&redirect_uri=http://localhost`;
        window.open(authUrl, "_blank");
      });

      // 授權碼輸入框與啟用按鈕
      let authCode = "";
      const codeGroup = container.createDiv({ cls: "sync-form-group" });
      codeGroup.createDiv({ cls: "sync-form-label", text: "2. 授權碼 (Authorization Code)" });
      const codeRow = codeGroup.createDiv();
      codeRow.style.cssText = "display: flex; gap: 8px;";
      const codeInput = codeRow.createEl("input", {
        cls: "sync-input",
        type: "text",
        attr: { placeholder: "將跳轉後網址中的 ?code= 後方的代碼貼在此處" },
      });
      codeInput.style.flex = "1";
      codeInput.addEventListener("input", () => {
        let val = codeInput.value.trim();
        if (val.includes("code=")) {
          const match = val.match(/[?&]code=([^&]+)/);
          if (match) {
            val = match[1];
          }
        }
        authCode = val;
      });

      const exchangeBtn = codeRow.createEl("button", { cls: "sync-btn sync-btn-primary", text: "3. 啟用驗證" });
      exchangeBtn.addEventListener("click", async () => {
        let finalCode = authCode.trim();
        if (finalCode.includes("code=")) {
          const match = finalCode.match(/[?&]code=([^&]+)/);
          if (match) {
            finalCode = match[1];
          }
        }
        if (!finalCode) {
          new Notice("請先輸入授權碼");
          return;
        }
        const provider = this.plugin.getProvider();
        if (provider && provider.name === "Box") {
          const res = await (provider as any).authorizeWithCode(finalCode);
          new Notice(res.message);
          if (res.success) {
            this.plugin.saveSettings();
            this.display();
          }
        }
      });

      const helpText = container.createDiv({
        cls: "sync-connection-status",
        text: "說明：請先輸入 Client ID 與 Client Secret，點擊「1. 產生授權連結」並在瀏覽器登入授權。完成後網頁會顯示「無法連上這個網站（此為正常現象）」，請直接複製瀏覽器網址列 `code=` 後方的代碼，貼到下方輸入框點擊「3. 啟用驗證」即可完成永久授權。",
      });
      helpText.style.cssText = "background: rgba(251, 191, 36, 0.08); border: 1px solid rgba(251, 191, 36, 0.2); color: var(--text-muted);";
    }
  }

  private renderSyncSettings(): void {
    const { containerEl } = this;

    const section = containerEl.createDiv({ cls: "sync-section" });
    const title = section.createDiv({ cls: "sync-section-title" });
    title.setText("同步行為");

    const card = section.createDiv({ cls: "sync-card" });

    this.toggleField(card, "儲存時同步", "每次檔案變更後自動同步", this.plugin.settings.syncOnSave, (v) => {
      this.plugin.settings.syncOnSave = v;
      this.plugin.saveSettings();
    });

    const divider = card.createDiv({ cls: "sync-settings-divider" });

    this.toggleField(card, "在狀態列顯示上一次成功的同步", "在狀態列顯示上一次成功的同步的時間。", this.plugin.settings.showLastSyncInStatusBar, (v) => {
      this.plugin.settings.showLastSyncInStatusBar = v;
      this.plugin.saveSettings();
      this.plugin.syncStatusBar.setIdle();
    });

    const divider1_5 = card.createDiv({ cls: "sync-settings-divider" });

    this.toggleField(card, "同步設定檔", "同時同步 .obsidian 設定檔案", this.plugin.settings.syncConfig, (v) => {
      this.plugin.settings.syncConfig = v;
      this.plugin.saveSettings();
    });

    const divider2 = card.createDiv({ cls: "sync-settings-divider" });

    this.toggleField(card, "跳過隱藏檔", "忽略以 . 或 _ 開頭的檔案", this.plugin.settings.skipHidden, (v) => {
      this.plugin.settings.skipHidden = v;
      this.plugin.saveSettings();
    });

    const divider3 = card.createDiv({ cls: "sync-settings-divider" });

    this.inputField(card, "自動同步間隔（分鐘）", String(this.plugin.settings.syncInterval), (v) => {
      this.plugin.settings.syncInterval = parseInt(v) || 0;
      this.plugin.saveSettings();
      this.plugin.restartAutoSync();
    }, "0 = 停用");

    this.inputField(card, "跳過路徑（正則表達式）", this.plugin.settings.skipPaths.join(", "), (v) => {
      this.plugin.settings.skipPaths = v ? v.split(",").map((s) => s.trim()).filter(Boolean) : [];
      this.plugin.saveSettings();
    }, "*.tmp, archive/*，多個規則以逗號分隔");

    const divider4 = card.createDiv({ cls: "sync-settings-divider" });

    const modeSetting = card.createDiv({ cls: "sync-form-group" });
    modeSetting.createDiv({ cls: "sync-form-label", text: "同步模式 (Sync Mode)" });
    const modeSelect = modeSetting.createEl("select", { cls: "sync-input" });
    const modes = [
      { value: "bidirectional", label: "雙向同步 (Bidirectional Sync)" },
      { value: "upload-only", label: "單向備份 (Upload Only / Backup)" },
      { value: "download-only", label: "單向回復 (Download Only / Restore)" },
    ];
    for (const m of modes) {
      const opt = modeSelect.createEl("option", { value: m.value, text: m.label });
      if (m.value === (this.plugin.settings.syncMode || "bidirectional")) opt.selected = true;
    }
    
    const modeDesc = modeSetting.createDiv({ cls: "sync-toggle-desc" });
    modeDesc.style.marginTop = "6px";
    
    const updateDesc = (val: string) => {
      if (val === "upload-only") {
        modeDesc.setText("💡 單向備份：將本機的新增或修改單向同步上傳到雲端，不下載雲端的變更。適合做為雲端備份庫使用。");
      } else if (val === "download-only") {
        modeDesc.setText("💡 單向回復：將雲端檔案單向同步下載並覆蓋至本機，不發送本機的任何修改。適合在全新裝置上進行初始還原。");
      } else {
        modeDesc.setText("💡 雙向同步：自動比對本機與雲端的最新異動，將兩端檔案同步至最新狀態。若發生衝突則套用下方的衝突處理策略。");
      }
    };
    
    updateDesc(this.plugin.settings.syncMode || "bidirectional");
    
    modeSelect.addEventListener("change", () => {
      this.plugin.settings.syncMode = modeSelect.value;
      updateDesc(modeSelect.value);
      this.plugin.saveSettings();
    });

    const divider5 = card.createDiv({ cls: "sync-settings-divider" });

    const conflictSetting = card.createDiv({ cls: "sync-form-group" });
    const conflictLabel = conflictSetting.createDiv({ cls: "sync-form-label", text: "衝突處理策略" });
    const conflictSelect = conflictSetting.createEl("select", { cls: "sync-input" });
    const strategies = [
      { value: "keep-newer", label: "保留較新檔案" },
      { value: "keep-larger", label: "保留較大檔案" },
      { value: "smart", label: "智慧合併 (Smart Merge)" },
    ];
    for (const strat of strategies) {
      const opt = conflictSelect.createEl("option", { value: strat.value, text: strat.label });
      if (strat.value === this.plugin.settings.conflictStrategy) opt.selected = true;
    }
    conflictSelect.addEventListener("change", () => {
      this.plugin.settings.conflictStrategy = conflictSelect.value;
      this.plugin.saveSettings();
    });
  }

  private renderAdvancedSettings(): void {
    const { containerEl } = this;

    const section = containerEl.createDiv({ cls: "sync-section" });
    const title = section.createDiv({ cls: "sync-section-title" });
    title.setText("加密設定");

    const card = section.createDiv({ cls: "sync-card" });

    const lockState = card.createDiv({
      cls: `sync-connection-status ${this.plugin.settings.encryptionPassword ? "success" : "loading"}`,
    });
    lockState.setText(this.plugin.settings.encryptionPassword
      ? "端到端加密已啟用"
      : "加密已停用 — 檔案以明文儲存");

    this.inputField(card, "加密密碼", this.plugin.settings.encryptionPassword, (v) => {
      this.plugin.settings.encryptionPassword = v;
      this.plugin.saveSettings();
    }, "留空以停用加密", "password");
  }

  private renderSyncHistory(): void {
    const { containerEl } = this;

    const section = containerEl.createDiv({ cls: "sync-section" });
    const title = section.createDiv({ cls: "sync-section-title" });
    title.setText("同步記錄");

    const log = section.createDiv({ cls: "sync-card" });
    const logContainer = log.createDiv({ cls: "sync-log" });

    const entries = this.plugin.syncLog;
    if (entries.length === 0) {
      logContainer.createDiv({
        cls: "sync-empty-state",
        text: "尚無同步活動，點擊「立即同步」開始",
      });
      return;
    }

    for (const entry of entries) {
      const row = logContainer.createDiv({ cls: `sync-log-entry${entry.type === "sync-error" ? " error" : entry.type === "sync-complete" ? " success" : ""}` });
      const time = row.createSpan({ cls: "sync-log-time" });
      time.setText(new Date(entry.timestamp).toLocaleTimeString());
      const msg = row.createSpan({ cls: "sync-log-msg" });
      msg.setText(entry.message);
    }
  }

  private inputField(
    container: HTMLElement,
    label: string,
    value: string,
    onChange: (v: string) => void,
    placeholder?: string,
    type = "text"
  ): void {
    const group = container.createDiv({ cls: "sync-form-group" });
    group.createDiv({ cls: "sync-form-label", text: label });
    const input = group.createEl("input", {
      cls: "sync-input",
      type,
      value,
      attr: { placeholder: placeholder || "" },
    });
    input.addEventListener("input", () => onChange(input.value));
  }

  private formRow(container: HTMLElement, renderFn: () => void): void {
    const row = container.createDiv({ cls: "sync-form-row" });
    renderFn();
  }

  private toggleField(
    container: HTMLElement,
    label: string,
    desc: string,
    value: boolean,
    onChange: (v: boolean) => void
  ): void {
    const row = container.createDiv({ cls: "sync-toggle-row" });
    const info = row.createDiv({ cls: "sync-toggle-info" });
    info.createDiv({ cls: "sync-toggle-label", text: label });
    info.createDiv({ cls: "sync-toggle-desc", text: desc });

    const toggle = row.createEl("input", { type: "checkbox", attr: { "data-toggle": "" } });
    toggle.checked = value;
    toggle.addEventListener("change", () => onChange(toggle.checked));
  }
}
